// Map applies f to every element of s and returns a new slice of the results.
func Map[T, U any](s []T, f func(T) U) []U {
	out := make([]U, len(s))
	for i, v := range s {
		out[i] = f(v)
	}
	return out
}

func main() {
	nums := []int{1, 2, 3, 4}
	strs := Map(nums, func(n int) string { return strconv.Itoa(n) })
	fmt.Printf("%q\n", strs)
}
