// merge fans multiple input channels into one, closing it when all inputs drain.
func merge(chans ...<-chan int) <-chan int {
	out := make(chan int)
	var wg sync.WaitGroup
	for _, ch := range chans {
		wg.Add(1)
		go func(c <-chan int) {
			defer wg.Done()
			for v := range c {
				out <- v
			}
		}(ch)
	}
	go func() {
		wg.Wait()
		close(out)
	}()
	return out
}

func main() {
	a := producer(1, 2, 3)
	b := producer(4, 5, 6)

	count := 0
	for range merge(a, b) {
		count++
	}
	fmt.Println("received:", count)
}
